        trace(logName, "Ascension-Workflow-New-Persona-Rehire-Process start for identity: " + identityName);
        trace(logName, "Entering Step: "+wfcontext.getStep().getName());

        addMessage(wfcontext, "Identity for Rehire - " + identityDisplayName + " [" + identityName + "]");

        String rehireType =null;
        String conversionType = null;
        String workItemDesc = null;

        String oldSetIDLocation = null;
        String newSetIDLocation = null;
        String newType = null;
        String oldType = null;
        String newEmplClass = null;
        String oldEmplClass= null;
        String oldgStatus = null;
        String newgStatus = null;

        if(null != event){

        Identity oldIdentity = event.getOldObject();
        Identity newIdentity = event.getNewObject();

        newSetIDLocation = findSetIDLocation(newIdentity);
        oldSetIDLocation = findSetIDLocation(oldIdentity);

        newType = newIdentity.getStringAttribute("type");  
        oldType = oldIdentity.getStringAttribute("type"); 

        newEmplClass = newIdentity.getStringAttribute("employeeClass");   
        oldEmplClass= oldIdentity.getStringAttribute("employeeClass"); 

        newgStatus = newIdentity.getStringAttribute("gsuiteStatus");
        oldgStatus = oldIdentity.getStringAttribute("gsuiteStatus");

        debug(logName, "oldSetIDLocation: " + oldSetIDLocation + " newSetIDLocation: " + newSetIDLocation);
        debug(logName, "oldType: " + oldType + " newType: " + newType);
        debug(logName, "oldEmplClass: " + oldEmplClass + " newEmplClass: " + newEmplClass);

        } else if(null != inputMap){

        newType = inputMap.get("new_type");  
        oldType = inputMap.get("old_type"); 

        newEmplClass = inputMap.get("new_employee_class");   
        oldEmplClass= inputMap.get("old_employee_class"); 

        newgStatus = inputMap.get("new_gsuite_status"); 
        oldgStatus = inputMap.get("old_gsuite_status");

        }


        String networkID = findSamAccountNameForIdentity(identityName);

        //find the conversion type is emplClassChange or typeChange
        conversionType = findConversionTypeForIdentity(oldType, newType, oldEmplClass, newEmplClass);
        rehireType = findRehireTypeForIdentity(oldSetIDLocation, newSetIDLocation, conversionType);


        //Setting Message - RehireType in the task result 

        String message = getRehireTypeMessage(rehireType, conversionType);
        addMessage(wfcontext, "Rehire Type - " + message);

        workflow.put("networkID", networkID);
        workflow.put("conversionType", conversionType);

        //Setting the values needed for Market Transfer WorkItem Form

        if(Util.nullSafeCaseInsensitiveEq(rehireType, "Market Transfer")){
        if(isPersonaSETID(oldSetIDLocation) || isPersonaSETID(newSetIDLocation)){
        workflow.put("isPersonaMarketTransfer", true);
        } else{
        workflow.put("isPersonaMarketTransfer", false);
        }
        String workitemName = setWorkItemNameForMarketTransfer(oldSetIDLocation, newSetIDLocation, conversionType);
        workflow.put("oldSetIDLocation", oldSetIDLocation);
        workflow.put("newSetIDLocation", newSetIDLocation);
        workflow.put("rehireTypeDetails", workitemName);
        }

        if(null != conversionType && Util.nullSafeCaseInsensitiveEq(conversionType, "typeChange")){
        if(Util.isNullOrEmpty(oldType)){
        oldType = "Not Available";
        }
        if(Util.isNullOrEmpty(newType)){
        newType = "Not Available";
        }
        addMessage(wfcontext, "Old Type: " + oldType + " New Type: " + newType);
        workItemDesc = "Please note the user's Type changed from " + oldType + " to " + newType;
        workflow.put("oldTypeValue", oldType);
        workflow.put("newTypeValue", newType);
        workflow.put("userTypeWorkItemDesc", workItemDesc);
        } else if(null != conversionType && Util.nullSafeCaseInsensitiveEq(conversionType, "empClassChange")){
        if(Util.isNullOrEmpty(oldEmplClass)){
        oldEmplClass = "Not Available";
        }
        if(Util.isNullOrEmpty(newEmplClass)){
        newEmplClass = "Not Available";
        } 
        addMessage(wfcontext, "Old Employee Class: " + oldEmplClass + " New Employee Class: " + newEmplClass);
        workItemDesc = "Please note the user's Employee Class changed from " + oldEmplClass + " to " + newEmplClass;
        workflow.put("oldEmplClassValue", oldEmplClass);
        workflow.put("newEmplClassValue", newEmplClass);
        workflow.put("emplClassWorkItemDesc", workItemDesc);
        }

        if(null != conversionType && Util.nullSafeCaseInsensitiveEq(rehireType, "Type Transfer")){
        if(Util.isNotNullOrEmpty(oldgStatus) || Util.isNotNullOrEmpty(newgStatus)){
        if(Util.isNullOrEmpty(oldgStatus)){
        oldgStatus = "Not Available";
        }
        if(Util.isNullOrEmpty(newgStatus)){
        newgStatus = "Not Available";
        }
        addMessage(wfcontext, "Old GSuite Status: " + oldgStatus + " New GSuite Status: " + newgStatus);
        }
        }

        //update the contractor expiration date for Non-Persona users
        updateContractorExpirationDate(identityName);

        trace(logName, "Exiting Step: "+wfcontext.getStep().getName());
        return rehireType;

if(wfcase.hasErrors()){
workflow.put("stepName" , wfcontext.getStep().getName());
return true;
} else{
return false;
}

          trace(logName, "Entering Step: "+wfcontext.getStep().getName());
        //isInMinistriesList method checks if the identity is in the persona enabled ministry
        boolean isInPersonaEnabledMinistry = isInMinistriesList(identityName);
        debug(logName, "Is in Persona Enabled Ministry: " + isInPersonaEnabledMinistry);
        trace(logName, "Exiting Step: "+wfcontext.getStep().getName());

        return isInPersonaEnabledMinistry;

if(wfcase.hasErrors()){
workflow.put("stepName" , wfcontext.getStep().getName());
return true;
} else{
return false;
}

        import sailpoint.object.Identity;

        trace(logName, "Entering Step: "+wfcontext.getStep().getName());

        boolean needsRefresh = false;


        Identity rehiredIdentity = context.getObjectByName(Identity.class,identityName);
        String personaType = rehiredIdentity.getAttribute("personaType");
        String parentPersonaName = rehiredIdentity.getAttribute("parentPersonaName");

        if(null!=personaType && !personaType.isEmpty() && null!=parentPersonaName) 
        {
        //rehired identity is primary profile
        if("Primary".equalsIgnoreCase(personaType))
        {
        //Write Audit records to IIQ.
        String auditString1 = "Identity that is rehired: "+identityName;
        String auditString2 = "Persona type: "+personaType;
        String auditString3 = "Triggering Rehire Workflow for the identity: "+identityName;
        writeAuditRecordToIIQ("PersonaRehire",auditString1, auditString2,auditString3,identityName,"Persona Rehire");


        //Rehired identity is a parent profile. Rehire workflow will take care of reenabling its accounts / links
        }
        else 
        {
        //rehired identity is a child profile
        needsRefresh  = true;
        Identity parentIdentity = context.getObjectByName(Identity.class,parentPersonaName);

        boolean parentStatus = getIdentityStatus(parentIdentity.getName());

        String parentProfileType = parentIdentity.getAttribute("identityType");

        if(null==parentProfileType)
        {
        parentProfileType = getProfileType(parentIdentity.getName());
        }

        String rehiredProfileType = rehiredIdentity.getAttribute("identityType");
        if(null==rehiredProfileType)
        {
        rehiredProfileType = getProfileType(rehiredIdentity.getName());
        }


        boolean result = 
        (
        (parentStatus && parentProfileType.equalsIgnoreCase("ProviderPersona") && rehiredProfileType.equalsIgnoreCase("EmployeePersona"))
        ||
        (parentStatus && parentProfileType.equalsIgnoreCase("NonHRContractorPersona") && rehiredProfileType.equalsIgnoreCase("EmployeePersona"))
        ||
        (parentStatus && parentProfileType.equalsIgnoreCase("NonHRContractorPersona") && rehiredProfileType.equalsIgnoreCase("ProviderPersona"))
        ||
        (parentStatus && parentProfileType.equalsIgnoreCase("NonHRContractorPersona") && rehiredProfileType.equalsIgnoreCase("ContractorPersona"))
        ||
        (parentStatus && parentProfileType.equalsIgnoreCase("ContractorPersona") && rehiredProfileType.equalsIgnoreCase("EmployeePersona"))
        ||
        (parentStatus && parentProfileType.equalsIgnoreCase("ContractorPersona") && rehiredProfileType.equalsIgnoreCase("ProviderPersona"))
        ||
        (parentStatus && parentProfileType.equalsIgnoreCase("OtherPersona") && rehiredProfileType.equalsIgnoreCase("EmployeePersona"))
        ||
        (parentStatus && parentProfileType.equalsIgnoreCase("OtherPersona") && rehiredProfileType.equalsIgnoreCase("ProviderPersona"))
        ||
        (parentStatus && parentProfileType.equalsIgnoreCase("OtherPersona") && rehiredProfileType.equalsIgnoreCase("ContractorPersona"))
        ||
        (!parentStatus)
        );

        //Special Linking  - PC Linking,Move Accounts, Move Roles from MI to II
        //Normal Linking 

        if(!result)
        {

        //Write Audit records to IIQ.
        String auditString1 = "Identity that was rehired: "+identityName;
        String auditString2 = "Persona Type: "+personaType;
        String auditString3 = "Triggering the Rehire Workflow on the identity : "+identityName;
        writeAuditRecordToIIQ("PersonaRehire" ,auditString1, auditString2,auditString3,identityName,"Persona Rehire");

        //Normal Linking - Proceed to call enable user subprocess to enable accounts
        }
        else
        {
        //Special Linking case.
        List childPersonaList = parentIdentity.getAttribute("childPersonas");
        boolean setProtectedFlag = false;
        String tempParentInternalId = parentIdentity.getAttribute("internalId");
        String tempLeaverDate = parentIdentity.getAttribute("leaverDate");
        String tempSamAccName = parentIdentity.getAttribute("samAccountName");

        Identity newParentIdentity = context.getObjectByName(Identity.class,identityName);
        if(null!=newParentIdentity)
        {
        newParentIdentity.setAttribute("personaType","Primary");
        newParentIdentity.removeAttribute("parentPersonaName");
        newParentIdentity.removeAttribute("parentPersonaSID");
        newParentIdentity.setAttribute("identityType",rehiredProfileType);
        childPersonaList.remove(newParentIdentity.getAttribute("internalId"));
        childPersonaList.add(parentIdentity.getAttribute("internalId"));

        parentIdentity.setAttribute("personaType","Child");
        parentIdentity.removeAttribute("childPersonas");
        parentIdentity.removeAttribute("childPersonaNames");
        parentIdentity.setAttribute("identityType",parentProfileType);
        parentIdentity.setAttribute("parentPersonaName",newParentIdentity.getName());
        parentIdentity.setAttribute("parentPersonaSID",newParentIdentity.getAttribute("internalId"));
        parentIdentity.setAttribute("samAccountName","");
        //parentIdentity.removeAttribute("initialName");

        context.saveObject(parentIdentity);
        context.commitTransaction();
        //comment decache //context.decache(parentIdentity);

        newParentIdentity.setAttribute("childPersonas", childPersonaList);
        List childNamesStr = getChildIdentities(childPersonaList);

        newParentIdentity.setAttribute("childPersonaNames", childNamesStr);
        newParentIdentity.setAttribute("leaverDate", tempLeaverDate);
        
        if(!checkIfValidADAccountExists(parentPersonaName)){
        needsRefresh  = false;
        newParentIdentity.setAttribute("samAccountName", tempSamAccName);
        }

        context.saveObject(newParentIdentity);
        context.commitTransaction();
        //comment decache //context.decache(newParentIdentity);

        //Update parent identities details in secondary identities
        updateParentPersonaAttributesInSecondaryIdentities(childPersonaList,identityName);

        boolean linkedMovedSuccess = false;
        try
        {
        moveIdentityLinks(parentPersonaName,identityName);
        linkedMovedSuccess = true;
        }
        catch(Exception e)
        {
        error(logName, "Error in executing moveIdentityLinks method" + e);
        }
        
        List assignedRolesList = getBirthRightAssignedRolesForIdentity(parentPersonaName);
        removeBirthRightRolesFromIdentity(parentPersonaName);
        if(linkedMovedSuccess)
        {
        //Check if the old identity from which links were moved has any links. 
        //If no links are there then mark it as protected, set protected=true, and if any links are there set protected = false
        boolean linksPresent = checkIfLinksExistOnIdentity(parentPersonaName);
        if(!linksPresent)
        {
        setProtectedFlag = true;
        }

        addBirthRightRolesToIdentity(identityName,assignedRolesList);
        }

        //Write Audit records to IIQ.
        String auditString1 = "New Parent (Primary) Identity: "+identityName;
        String auditString2 = "Old Parent (Primary) Identity: "+parentPersonaName;
        String auditString3 = "Birthright links and roles moved from : "+parentPersonaName + " to "+identityName;
        writeAuditRecordToIIQ("PersonaRehire" ,auditString1, auditString2,auditString3,identityName,"Persona Rehire");
        }
        
        //Username rename scenario logic
        Identity latestParentIden = context.getObjectByName(Identity.class,identityName);
        Identity latestChildIden = context.getObjectByName(Identity.class,parentPersonaName);

        String initialName = latestChildIden.getAttribute("initialName");
        boolean nameChangeNeededForNewParent = checkIfUserNameNeedsToBeChanged(identityName);

        if(null!=initialName && nameChangeNeededForNewParent)
        {
        //move usernames
        //samaccountname is on the latestChildIden name.
        //initialname is on the latestChildIden
        //rehired identity name is on the latestParentIden name

        //latestParentIden should be renamed using samaccountname (which is name of latestChildIden)
        //intial name should be set as child identity name;
        //rehired identity name to be stored as initialName on the latestParentIden 

        String samName = latestChildIden.getName();
        String initName = initialName;
        String inIdenName = latestParentIden.getName();

        latestChildIden.setName(initName);

        try
        {
        context.saveObject(latestChildIden);
        context.commitTransaction();
        //comment decache //context.decache(latestChildIden);
        }
        catch(Exception e)
        {
        error(logName, "Error in saving the latestChildIden " + e);
        }

        latestParentIden.setName(samName);
        latestParentIden.setAttribute("initialName",inIdenName);

        try
        {
        context.saveObject(latestParentIden);
        context.commitTransaction();
        //comment decache //context.decache(latestParentIden);
        }
        catch(Exception e)
        {
        error(logName, "Error in saving the latestParentIden " + e);
        }

        Identity latestChildIdentity = context.getObjectByName(Identity.class,initName);
        Identity latestParentIdentity = context.getObjectByName(Identity.class,samName);
        List chdPersonaList = latestParentIdentity.getAttribute("childPersonas");

        List childNamesStr = getChildIdentities(childPersonaList);
        latestParentIdentity.setAttribute("childPersonaNames", childNamesStr);

        //Update primary identities details in child identities
        updateParentPersonaAttributesInSecondaryIdentities(childPersonaList,samName);

        try
        {
        context.saveObject(latestParentIdentity);
        context.commitTransaction();
        //comment decache //context.decache(latestParentIdentity);
        }
        catch(Exception e)
        {
        error(logName, "Error in saving the latestParentIdentity " + e);
        }

        workflow.put("modifiedName",samName);
        workflow.put("identityName",samName);


        if(null!=initialName)
        {
        auditString1 = "Based on the username move criteria, username moved from Child Identity to Parent Identity";
        auditString2 = "Incoming identity (New Parent) username now is:"+ workflow.get("modifiedName") + " from earlier username: "+identityName;
        auditString3 = "Matching identity (New Child) username now is:"+ initialName+ " from earlier username: "+parentPersonaName;
        writeAuditRecordToIIQ("PersonaUsernameMove",auditString1, auditString2,auditString3,workflow.get("modifiedName"),"Persona Rehire");
        }

        if(setProtectedFlag)
        {
        Identity tempChildIden = context.getObjectByName(Identity.class,initialName);

        tempChildIden.setProtected(setProtectedFlag);
        tempChildIden.setAttribute("samAccountName","");
        context.saveObject(tempChildIden);
        context.commitTransaction();
        //comment decache //context.decache(tempChildIden);
        }
        }
        else
        {
        if(setProtectedFlag)
        {
        Identity tempChildIden = context.getObjectByName(Identity.class,latestChildIden.getName());

        tempChildIden.setProtected(setProtectedFlag);
        tempChildIden.setAttribute("samAccountName","");
        context.saveObject(tempChildIden);
        context.commitTransaction();
        //comment decache //context.decache(tempChildIden);
        }
        }
        }//end else
        }//rehired identity is child profile
        }//personaType not null
        else
        {
        //Write Audit records to IIQ.
        String auditString1 = "Identity that is rehired: "+identityName;
        String auditString2 = "Persona type: "+personaType;
        String auditString3 = "Triggering Rehire Workflow for the identity: "+identityName;
        writeAuditRecordToIIQ("PersonaRehire",auditString1, auditString2,auditString3,identityName,"Persona Rehire");

        //Not marked by the Persona Module. Just trigger the rehire  
        } 
        trace(logName, "Exiting Step: "+wfcontext.getStep().getName());
        return needsRefresh;

if(wfcase.hasErrors()){
workflow.put("stepName" , wfcontext.getStep().getName());
return true;
} else{
return false;
}

